        val content = envelope.getString("content")
        require(contentHash == "sha256:${sha256(content)}") { "runtime bundle hash mismatch" }
        val decoded = JSONObject(content)
        manifest = decoded.getJSONObject("manifest")
        payload = decoded.getJSONObject("payload")
        val compatibility = manifest.getJSONObject("compatibility")
        require(manifest.getString("format") == "oscarui.runtime.bundle" && manifest.getInt("bundleVersion") == 1)
        require(RUNTIME_API in compatibility.getInt("minRuntimeApi")..compatibility.getInt("maxRuntimeApi"))
        require(compatibility.getInt("uiSchemaVersion") == UI_SCHEMA_VERSION)
