    val navigationAnimationsEnabled: Boolean get() = appConfig.optJSONObject("navigation")?.string("animation", "platform") != "none"
    fun screen(name: String): JSONObject? = screens.firstOrNull { it.string("screen") == name }
    fun component(name: String): JSONObject? = components.firstOrNull { it.string("component") == name }
}

class RuntimeBundleLoader(private val context: Context) {
    private val directory = File(context.filesDir, "runtime")
    private val current = File(directory, "current.json")
    private val lastGood = File(directory, "last-good.json")

    fun loadInitial(): RuntimeBundle {
        for (file in listOf(current, lastGood)) {
            if (file.exists()) runCatching { return RuntimeBundle(file.readBytes()) }
        }
        return RuntimeBundle(context.assets.open("oscarui.runtime.json").use { it.readBytes() })
    }

    fun activate(data: ByteArray): RuntimeBundle {
        val bundle = RuntimeBundle(data)
        directory.mkdirs()
        if (current.exists()) current.copyTo(lastGood, overwrite = true)
        val pending = File(directory, "current.pending")
        pending.writeBytes(data)
        if (current.exists()) current.delete()
        require(pending.renameTo(current)) { "could not activate runtime bundle" }
        return bundle
    }
}

class RuntimeBundleStore(private val context: Context) {
    private val loader = RuntimeBundleLoader(context)
    var bundle by mutableStateOf(loader.loadInitial())
        private set

    fun fetchRemoteUpdateIfConfigured() {
        val runtime = bundle.appConfig.optJSONObject("runtime") ?: return
        if (!runtime.optBoolean("allowRemoteUpdates")) return
        val url = runtime.string("remoteBundleURL")
        if (!url.startsWith("https://")) return
        val timeout = runtime.optInt("requestTimeoutSeconds", 15) * 1000
        Thread {
            runCatching {
                val connection = URL(url).openConnection() as HttpURLConnection
                connection.connectTimeout = timeout
                connection.readTimeout = timeout
                connection.setRequestProperty("If-None-Match", bundle.contentHash)
                if (connection.responseCode == HttpURLConnection.HTTP_NOT_MODIFIED) return@runCatching
                require(connection.responseCode in 200..299)
                val data = connection.inputStream.use { it.readBytes() }
                val next = RuntimeBundle(data)
                if (next.contentHash != bundle.contentHash) {
                    Handler(Looper.getMainLooper()).post { bundle = loader.activate(data) }
                }
            }.onFailure { android.util.Log.w("OscarUI", "Runtime update rejected", it) }
        }.start()
    }
}

class RuntimeScreenState(screen: JSONObject) {
    val values: SnapshotStateMap<String, Any> = mutableStateMapOf()
    val lists: Map<String, List<Map<String, Any>>>

    init {
        val listValues = mutableMapOf<String, List<Map<String, Any>>>()
