                listValues[name] = (0 until rows.length()).mapNotNull { rows.optJSONObject(it) }.map { row ->
                    row.keys().asSequence().associateWith { key -> row.opt(key).runtimeValue() }
                }
            } else {
                values[name] = state.opt("default").runtimeValue()
            }
        }
        lists = listValues
    }
}

private fun Any?.runtimeValue(): Any = when (this) {
    null, JSONObject.NULL -> ""
    is String, is Boolean, is Int, is Long, is Double, is Float -> this
    is Number -> toDouble()
    else -> toString()
}
private fun Any?.display(): String = when (this) { null -> ""; is Boolean -> toString(); else -> this.toString() }
private fun Any?.truthy(): Boolean = when (this) { is Boolean -> this; is Number -> toDouble() != 0.0; is String -> isNotEmpty(); else -> false }

