@Composable
private fun RuntimeNode(
    node: JSONObject, screen: JSONObject, screenName: String, bundle: RuntimeBundle,
    state: RuntimeScreenState, navigator: RuntimeNavigator, actions: RuntimeNativeActions,
    context: RuntimeContext, modifier: Modifier = Modifier,
) {
    fun resolve(binding: String): Any = when {
        binding.startsWith("item.") -> context.item[binding.removePrefix("item.")] ?: ""
        context.props.containsKey(binding) -> context.props[binding] ?: ""
        else -> state.values[binding] ?: ""
    }
    fun visible(): Boolean {
        val condition = node.optJSONObject("visibleWhen") ?: return true
        val actual = resolve(condition.string("state"))
        return when { condition.has("equals") -> actual == condition.opt("equals").runtimeValue(); condition.has("notEquals") -> actual != condition.opt("notEquals").runtimeValue(); else -> actual.truthy() }
    }
    fun perform(requested: String) {
        var action = requested
        val seen = mutableSetOf<String>()
        while (context.actionProps.containsKey(action) && seen.add(action)) action = context.actionProps[action].orEmpty()
        actions.invoke(screenName, action)
        val declaration = screen.objects("actions").firstOrNull { it.string("name") == action } ?: return
        val navigation = declaration.optJSONObject("navigation") ?: return
        when (navigation.string("type")) { "push" -> navigator.navigate(navigation.string("screen")); "pop" -> navigator.pop() }
    }
    if (!visible()) return
    val tokens = RuntimeTokens(bundle.tokens)
    when (node.string("type")) {
        "column" -> Column(
            modifier = modifier.padding(tokens.spacing(node.string("padding", "none"))),
            verticalArrangement = Arrangement.spacedBy(tokens.spacing(node.string("spacing", "normal"))),
            horizontalAlignment = when (node.string("align", "center")) { "start" -> Alignment.Start; "end" -> Alignment.End; else -> Alignment.CenterHorizontally }
        ) { node.objects("children").forEach { RuntimeNode(it, screen, screenName, bundle, state, navigator, actions, context) } }
        "row" -> Row(
            modifier = modifier.padding(tokens.spacing(node.string("padding", "none"))),
            horizontalArrangement = Arrangement.spacedBy(tokens.spacing(node.string("spacing", "normal"))),
            verticalAlignment = when (node.string("align", "center")) { "start" -> Alignment.Top; "end" -> Alignment.Bottom; else -> Alignment.CenterVertically }
        ) { node.objects("children").forEach { RuntimeNode(it, screen, screenName, bundle, state, navigator, actions, context) } }
        "text" -> Text(
            text = if (node.has("bind")) resolve(node.string("bind")).display() else node.string("value"),
            style = tokens.textStyle(node.string("role", "body")), color = tokens.color(node.string("color", "textPrimary")), modifier = modifier
        )
        "image" -> AsyncImage(
            model = node.string("url"), contentDescription = null, contentScale = ContentScale.Crop,
            modifier = modifier.fillMaxWidth().then(if (node.has("height")) Modifier.height(node.getDouble("height").dp) else Modifier).clip(RoundedCornerShape(tokens.radius(node.string("radius", "none"))))
        )
        "button" -> RuntimeButton(node, tokens, modifier) { perform(node.string("action")) }
        "textField" -> {
            val binding = node.string("bind")
            OutlinedTextField(
                value = state.values[binding].display(), onValueChange = { state.values[binding] = it },
                placeholder = { Text(node.string("placeholder"), style = tokens.textStyle("body"), color = tokens.color("placeholder")) },
                visualTransformation = if (node.optBoolean("secure")) PasswordVisualTransformation() else androidx.compose.ui.text.input.VisualTransformation.None,
                keyboardOptions = KeyboardOptions(keyboardType = when (node.string("keyboard", "default")) { "email" -> KeyboardType.Email; "number" -> KeyboardType.Number; "phone" -> KeyboardType.Phone; else -> KeyboardType.Text }),
                singleLine = true, textStyle = tokens.textStyle("body"), shape = RoundedCornerShape(tokens.radius("normal")),
                colors = OutlinedTextFieldDefaults.colors(focusedTextColor = tokens.color("textPrimary"), unfocusedTextColor = tokens.color("textPrimary"), focusedBorderColor = tokens.color("primary"), unfocusedBorderColor = tokens.color("border"), focusedContainerColor = tokens.color("fieldBackground"), unfocusedContainerColor = tokens.color("fieldBackground")),
                modifier = modifier.fillMaxWidth().height(tokens.size("controlHeight"))
            )
        }
        "list" -> {
            val items = state.lists[node.string("bind")].orEmpty()
            Column(modifier.clip(RoundedCornerShape(tokens.radius("normal"))).background(tokens.color("listRowBackground"))) {
                items.forEachIndexed { index, item ->
                    RuntimeNodeGroup(node.objects("itemTemplate"), screen, screenName, bundle, state, navigator, actions, RuntimeContext(context.props, context.actionProps, item))
                    if (index < items.lastIndex) HorizontalDivider(Modifier.padding(start = tokens.spacing("normal")), color = tokens.color("border"), thickness = tokens.size("borderWidth"))
                }
            }
        }
        "listRow" -> Row(
            modifier = modifier.fillMaxWidth().background(tokens.color("listRowBackground")).clickable { perform(node.string("action")) }.heightIn(min = tokens.size("listRowMinHeight")).padding(horizontal = tokens.spacing("normal"), vertical = tokens.spacing("tight")),
            verticalAlignment = Alignment.CenterVertically, horizontalArrangement = Arrangement.spacedBy(tokens.spacing("normal"))
        ) {
            Column(Modifier.weight(1f), verticalArrangement = Arrangement.spacedBy(tokens.spacing("tight"))) {
                Text(if (node.has("titleBind")) resolve(node.string("titleBind")).display() else node.string("title"), style = tokens.textStyle("body"), color = tokens.color("textPrimary"))
                if (node.has("subtitle") || node.has("subtitleBind")) Text(if (node.has("subtitleBind")) resolve(node.string("subtitleBind")).display() else node.string("subtitle"), style = tokens.textStyle("caption"), color = tokens.color("textSecondary"))
            }
            Text("›", style = tokens.textStyle("heading"), color = tokens.color("chevron"))
        }
        "component" -> bundle.component(node.string("name"))?.let { component ->
            val supplied = node.optJSONObject("props") ?: JSONObject()
            val props = mutableMapOf<String, Any>()
            val actionProps = context.actionProps.toMutableMap()
            for (definition in component.objects("props")) {
                val name = definition.string("name")
                val value = supplied.opt(name)
                if (definition.string("type") == "action") actionProps[name] = value as? String ?: ""
                else if (value is String && (value.startsWith("item.") || state.values.containsKey(value) || context.props.containsKey(value))) props[name] = resolve(value)
                else props[name] = value.runtimeValue()
            }
            RuntimeNodeGroup(component.objects("body"), screen, screenName, bundle, state, navigator, actions, RuntimeContext(props, actionProps, context.item), modifier)
        }
        "spacer" -> Spacer(modifier)
        else -> Text("Unsupported runtime node: ${node.string("type")}", color = Color.Red)
    }
}

@Composable
private fun RuntimeButton(node: JSONObject, tokens: RuntimeTokens, modifier: Modifier, onClick: () -> Unit) {
    val role = node.string("role", "primary")
    val content: @Composable () -> Unit = { Text(node.string("label"), style = tokens.textStyle("body")) }
    val sized = modifier.height(tokens.size("controlHeight")).widthIn(min = tokens.size("buttonMinWidth"))
    when (role) {
        "primary" -> Button(onClick, sized, colors = ButtonDefaults.buttonColors(containerColor = tokens.color("primary"), contentColor = tokens.color("onPrimary")), shape = RoundedCornerShape(tokens.radius("large")), content = { content() })
        "secondary" -> OutlinedButton(onClick, sized, colors = ButtonDefaults.outlinedButtonColors(contentColor = tokens.color("primary")), border = BorderStroke(tokens.size("borderWidth"), tokens.color("border")), shape = RoundedCornerShape(tokens.radius("large")), content = { content() })
        else -> TextButton(onClick, sized, colors = ButtonDefaults.textButtonColors(contentColor = tokens.color("primary")), content = { content() })
    }
}

class RuntimeTokens(private val values: JSONObject) {
    private fun number(group: String, name: String): Double = values.optJSONObject(group)?.optDouble(name, 0.0) ?: 0.0
    fun spacing(name: String): Dp = number("spacing", name).dp
    fun radius(name: String): Dp = number("radius", name).dp
    fun size(name: String): Dp = number("size", name).dp
    fun color(name: String): Color = Color(android.graphics.Color.parseColor(values.optJSONObject("color")?.string(name, "#000000") ?: "#000000"))
    fun textStyle(name: String): TextStyle {
        val definition = values.optJSONObject("typography")?.optJSONObject(name) ?: JSONObject()
        val weight = when (definition.string("weight")) { "bold" -> FontWeight.Bold; "semibold" -> FontWeight.SemiBold; else -> FontWeight.Normal }
        return TextStyle(fontSize = definition.optDouble("size", 16.0).sp, fontWeight = weight)
    }
    fun contentWidthModifier(name: String): Modifier = when (name) {
        "fill" -> Modifier.fillMaxWidth()
        else -> Modifier.widthIn(max = size("content" + name.replaceFirstChar { it.uppercase() })).fillMaxWidth()
    }
}
